set-variable.value:
#[%dw 2.0
output application/json

var isForwards = vars.parameters.targetDirection == "forwards"
var hasTarget = vars.parameters.targetId != null

// Flattening conditional arrays avoids mixing Null and String types
var whereClauses: Array<String> = flatten([
    if (vars.parameters.filters.status?) ["Status__c = ':status'"] else [],
    if (vars.parameters.q != null) ["Name LIKE ':q'"] else [],
    if (hasTarget and isForwards) ["UUID__c > ':targetId'"] else [],
    if (hasTarget and !isForwards) ["UUID__c < ':targetId'"] else []
])

var whereString: String = if (isEmpty(whereClauses)) "" else "WHERE " ++ (whereClauses joinBy " AND ")

var orderString: String = if (isForwards) "ORDER BY UUID__c ASC" else "ORDER BY UUID__c DESC"

// Wrap conditional strings in arrays so flatten handles them cleanly
var queryParts: Array<String> = flatten([
    ["SELECT UUID__c, Name, Email__c, Phone__c, Website__c, Status__c, CreatedDate, LastModifiedDate FROM Supplier__c"],
    if (whereString != "") [whereString] else [],
    [orderString],
    ["LIMIT :limit"]
])
---
queryParts joinBy " "]

salesforce:query-all.salesforce:parameters:
#[%dw 2.0
output application/json
---
{
    limit: vars.parameters.limit default 25,

    // Conditionally include keys only if the data exists
    (status: vars.parameters.filters.status) if (vars.parameters.filters.status?),
    (q: "%" ++ vars.parameters.q as String ++ "%") if (vars.parameters.q != null),
    (targetId: vars.parameters.targetId) if (vars.parameters.targetId != null)
}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
import * from dataweave::util::Pagination
import * from dw::core::Binaries
var rawDbResults = payload default []
var requestedLimit = (vars.parameters.limit default 25) as Number
var incomingDirection = vars.parameters.targetDirection default "forward"
var hasIncomingToken = (vars.parameters.before != null) or (vars.parameters.after != null)
var currentFilters = vars.parameters.filters default {
}
var hasExtraRecord = sizeOf(rawDbResults) > requestedLimit
var slicedResults = if ( hasExtraRecord ) rawDbResults[0 to (requestedLimit - 1)] else rawDbResults
var finalResults = if ( incomingDirection == "backward" ) slicedResults[-1 to 0] else slicedResults
var firstRecord = finalResults[0] default null
var lastRecord = finalResults[-1] default null
var wasMovingBackward = incomingDirection == "backward"
var wasMovingForward = incomingDirection == "forward"
var hasNext = if ( wasMovingForward ) hasExtraRecord else true
var hasPrevious = if ( wasMovingBackward ) hasExtraRecord else (wasMovingForward and hasIncomingToken)
---
{
	paging: {
		cursors: {
			before: if ( hasPrevious ) serializeToken(firstRecord, "backward", requestedLimit, currentFilters) else null,
			after: if ( hasNext ) serializeToken(lastRecord, "forward", requestedLimit, currentFilters) else null
		},
		hasNext: hasNext,
		hasPrevious: hasPrevious,
		limit: requestedLimit
	},
	results: finalResults map {
		id: $.UUID__c,
		name: $.Name,
		email: $.Email__c,
		phone: $.Phone__c default null,
		website: $.Website__c default null,
		status: $.Status__c
	}
}
